import React, { useRef } from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import { Navigation, Autoplay } from "swiper/modules";
import { useNavigate } from "react-router-dom";

// Импорт стилей Swiper
import "swiper/css";
import "swiper/css/navigation";

// Тестовые данные (заглушки), чтобы карточки появились сразу
const staticMovies = [
  { id: 1, title: "Movie 1", poster_path: "data:image/jpeg;base64," },
  { id: 2, title: "Movie 2", poster_path: "data:image/jpeg;base64," },
  { id: 3, title: "Movie 3", poster_path: "data:image/jpeg;base64," },
  { id: 4, title: "Movie 4", poster_path: "data:image/jpeg;base64," },
  { id: 5, title: "Movie 5", poster_path: "data:image/jpeg;base64," },
  { id: 6, title: "Movie 6", poster_path: "data:image/jpeg;base64," },
];

function Slider() {
  const prevRef = useRef(null);
  const nextRef = useRef(null);
  const navigate = useNavigate();

  // Функция для перехода на страницу фильма
  const handleOpen = (id) => {
    navigate(`/movie/${id}`);
  };

  return (
    <section className="bg-black px-6 md:px-16 py-14">
      {/* Header & Navigation Buttons */}
      <div className="mb-8 block md:flex items-end justify-between max-w-[1700px] mx-auto px-6">
        <div>
          <h2 className="text-white text-2xl md:text-3xl font-semibold mb-2">
            Explore our wide variety of categories
          </h2>
          <p className="text-gray-400 max-w-2xl text-sm md:text-base">
            Whether you're looking for a comedy, a drama, or a documentary.
          </p>
        </div>

        {/* Custom Navigation Arrows */}
        <div className="flex gap-5 w-32 h-12 bg-[#1a1a1a] rounded-lg items-center justify-center mt-10 md:mt-0">
          <button
            ref={prevRef}
            className="w-12 h-10 rounded-[10px] bg-black text-white hover:bg-[#2a2a2a] transition text-[20px]"
          >
            ←
          </button>
          <button
            ref={nextRef}
            className="w-12 h-10 rounded-[10px] bg-black text-white hover:bg-[#2a2a2a] transition text-[20px]"
          >
            →
          </button>
        </div>
      </div>

      {/* Swiper Slider */}
      <Swiper
        modules={[Navigation, Autoplay]}
        loop={true}
        autoplay={{
          delay: 3000,
          disableOnInteraction: false,
        }}
        speed={600}
        spaceBetween={20}
        // Настройка кастомных кнопок
        // eslint-disable-next-line react-hooks/refs
        navigation={{
          prevEl: prevRef.current,
          nextEl: nextRef.current,
        }}
        onBeforeInit={(swiper) => {
          swiper.params.navigation.prevEl = prevRef.current;
          swiper.params.navigation.nextEl = nextRef.current;
        }}
        breakpoints={{
          320: { slidesPerView: 1 },
          640: { slidesPerView: 2 },
          1024: { slidesPerView: 4 },
          1400: { slidesPerView: 5 },
        }}
        className="max-w-[1700px] mx-auto"
      >
        {staticMovies.map((movie) => (
          <SwiperSlide key={movie.id} onClick={() => handleOpen(movie.id)}>
            <div className="bg-[#0f0f0f] rounded-xl p-3 hover:scale-[1.05] transition cursor-pointer border border-[#1a1a1a]">
              <div className="relative overflow-hidden rounded-lg">
                <img
                  src={movie.poster_path}
                  alt={movie.title}
                  className="w-full h-64 object-cover"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
              </div>
              <h3 className="text-white mt-4 font-medium text-sm truncate">
                {movie.title}
              </h3>
            </div>
          </SwiperSlide>
        ))}
      </Swiper>
    </section>
  );
}

export default Slider;